(t) => {
    noFill(); strokeWeight(1.2);
    for (let i = 0; i < 5; i++) {
      const r = W(t, {wave:'wobble sine', seed:100+i, range:[4,20-i*2]});
      stroke(200-i*30, 100+i*30, 255, 200);
      ellipse(25, 25, r*2, r*2);
    }
  }

(t) => {
    noFill(); stroke(255,180,100); strokeWeight(1);
    beginShape();
    for (let i = 0; i < 8; i++) {
      const a = i*TWO_PI/8;
      const r = W(a, {wave:'bumpy sine', t:t, seed:110, range:[8,20]});
      vertex(25+cos(a)*r, 25+sin(a)*r);
    }
    endShape(CLOSE);
  }

(t) => {
    noStroke();
    for (let i = 0; i < 6; i++) {
      const w = W(t, {wave:'pulse', seed:120+i, range:[2,8]});
      const h = W(t*0.7, {wave:'pulse', seed:121+i, range:[3,12]});
      fill(W(i*0.3,{seed:125+i,t:t,range:[80,255]}), 100, 200);
      rect(4+i*7, 25-h/2, w, h, 1);
    }
  }

(t) => {
    noStroke();
    for (let i = 0; i < 15; i++) {
      const x = W(i*0.2, {wave:'up down noise', t:t, seed:190, range:[3,47]});
      const y = W(i*0.2, {wave:'up down noise', t:t*0.7, seed:191, range:[3,47]});
      const sz = W(i, {wave:'up down noise', t:t, seed:192, range:[2,7]});
      fill(W(i,{seed:193,t:t,range:[150,255]}), 100, 200, 180);
      ellipse(x, y, sz, sz);
    }
  }

(t) => {
    noStroke();
    const pulse = W(t, {wave:'grow random', seed:250, range:[0.3,1]});
    for (let i = 6; i >= 0; i--) {
      const a = map(i,6,0,5,200) * pulse;
      fill(255, 0, W(t,{wave:'grow random',seed:251,range:[100,255]}), a);
      ellipse(25, 25, 8+i*6, 8+i*6);
    }
  }

(t) => {
    colorMode(HSB,360,100,100); noStroke();
    for (let r = 0; r < 5; r++) for (let c = 0; c < 5; c++) {
      const h = W((r*5+c)*0.1, {wave:'steps', t:t, seed:260, range:[0,360]});
      fill(h%360, 80, 85);
      rect(c*10, r*10, 10, 10);
    }
    colorMode(RGB);
  }

(t) => {
    colorMode(HSB,360,100,100); noStroke();
    for (let x = 0; x < 50; x += 2) {
      const v = W(x*0.06, {wave:'bald patch', t:t, seed:290, range:[0,100]});
      fill((x*7+t*30)%360, v, 90);
      rect(x, 0, 2, 50);
    }
    colorMode(RGB);
  }

(t) => {
    noFill(); strokeWeight(1.5);
    const s = W(t, {wave:'fuzzy peak sine', seed:320, range:[8,40]});
    const rot = W(t, {wave:'fuzzy peak sine', seed:321, range:[0,PI/4]});
    stroke(W(t,{seed:322,wave:'sine',range:[100,255]}), 200, 255);
    push(); translate(25,25); rotate(rot); rectMode(CENTER);
    rect(0,0,s,s);
    pop();
  }

(t) => {
    noFill(); stroke(80,80,255,100); strokeWeight(0.8);
    beginShape();
    for (let x = 0; x < 50; x++) vertex(x, W(x*0.08,{wave:'wobble sine',t:t,seed:350,range:[10,40]}));
    endShape();
    const px = (t*15)%50;
    const py = W(px*0.08, {wave:'wobble sine',t:t,seed:350,range:[10,40]});
    noStroke(); fill(255,100,100);
    ellipse(px, py, 6, 6);
  }

(t) => {
    noStroke();
    fill(W(t,{seed:560,wave:'sine',range:[80,200]}), 220, 150);
    beginShape();
    for (let a = 0; a <= TWO_PI; a += 0.15) {
      const r = W(a, {wave:'bumpy sine', t:t, seed:561, range:[8,18]})
              + W(a*2, {wave:'noise', t:t*0.5, seed:562, range:[-3,3]});
      vertex(25+cos(a)*r, 25+sin(a)*r);
    }
    endShape(CLOSE);
    // Eyes
    fill(0); ellipse(22,22,3,3); ellipse(28,22,3,3);
  }

(t) => {
    noFill(); strokeWeight(1);
    for (let j = 0; j < 3; j++) {
      stroke(80, W(j,{seed:570+j,t:t,range:[150,255]}), 100);
      let x = 25, y = 48;
      beginShape();
      for (let i = 0; i < 25; i++) {
        const angle = W(i*0.15, {wave:'zig-zag sine', t:t+j, seed:573+j, range:[-PI/3,PI/3]}) - PI/2;
        x += cos(angle)*2; y += sin(angle)*2;
        vertex(x,y);
      }
      endShape();
    }
  }

(t) => {
    strokeWeight(1.5);
    for (let y = 0; y < 50; y += 2) {
      const x1 = 25 + W(y*0.08, {wave:'classic sine', t:t, seed:590, range:[-12,12]});
      const x2 = 25 + W(y*0.08, {wave:'classic sine', t:t, seed:590, range:[-12,12], phase:PI});
      const depth1 = W(y*0.08,{wave:'sine',t:t,seed:591,range:[0,1]});
      stroke(255*depth1,100,255*(1-depth1)); point(x1,y);
      stroke(255*(1-depth1),100,255*depth1); point(x2,y);
      if (y%6===0) { stroke(255,80); line(x1,y,x2,y); }
    }
  }

(t) => {
    noStroke();
    for(let y=0;y<50;y+=2)for(let x=0;x<50;x+=2){
      const n = noise(x*0.08,y*0.08,t*0.3);
      const w = W((x+y)*0.02,{wave:'valleys',t:t,seed:640,range:[0,1]});
      fill((n*0.5+w*0.5)*255); rect(x,y,2,2);
    }
  }

(t) => {
    noStroke();
    const off = floor(W(t,{wave:'saw up',seed:650,range:[0,50]}));
    const hShift = W(t,{wave:'triangle',seed:651,range:[0,100]});
    for(let y=0;y<50;y+=2)for(let x=0;x<50;x+=2){
      const v=((x+off)^y)%256;
      fill(v, v*0.6+hShift, 255-v); rect(x,y,2,2);
    }
  }

(t) => {
    noStroke();
    const cx1=15,cy1=15,cx2=35,cy2=15,cx3=25,cy3=38;
    for(let y=0;y<50;y+=2)for(let x=0;x<50;x+=2){
      const v1=W(dist(x,y,cx1,cy1)*0.1,{wave:'sine',t:t,seed:700,range:[-1,1]});
      const v2=W(dist(x,y,cx2,cy2)*0.1,{wave:'triangle',t:t,seed:701,range:[-1,1]});
      const v3=W(dist(x,y,cx3,cy3)*0.1,{wave:'square',t:t*0.5,seed:702,range:[-1,1]});
      fill(map(v1+v2+v3,-3,3,0,255),100,map(v1+v2+v3,-3,3,200,50));
      rect(x,y,2,2);
    }
  }

(t) => {
    noStroke();
    const waves = ['valleys','mountain peaks','noise','bumpy sine','sharp peaks'];
    for(let layer=0;layer<5;layer++){
      fill(20+layer*20, 40+layer*25, 60+layer*30, map(layer,0,4,80,240));
      beginShape(); vertex(0,50);
      for(let x=0;x<=50;x+=2){
        const y = 10+layer*8 + W(x*0.04,{wave:waves[layer],t:t*0.2+layer*0.5,seed:710+layer,range:[-8,8]});
        vertex(x,y);
      }
      vertex(50,50); endShape(CLOSE);
    }
  }

(t) => {
    noFill(); stroke(0,255,100); strokeWeight(1);
    beginShape();
    for(let i=0;i<100;i++){
      const u=i*0.05;
      const x=25+W(u,{wave:'wobble sine',t:t,seed:720,range:[-20,20]});
      const y=25+W(u,{wave:'batman',t:t,seed:721,range:[-20,20]});
      vertex(x,y);
    }
    endShape();
    stroke(0,255,100,30);strokeWeight(0.5);for(let y=0;y<50;y+=4)line(0,y,50,y);
  }

(t) => {
    noStroke();
    for(let r=0;r<3;r++)for(let c=0;c<3;c++){
      const h=W(r*3+c,{wave:'mountain peaks',seed:800,t:t,range:[4,18]});
      const ix=12+(c-r)*8,iy=20+(c+r)*5-h;
      fill(W(r*3+c,{seed:801,t:t,range:[120,200]}),180,255);
      quad(ix,iy,ix+8,iy-4,ix,iy-8,ix-8,iy-4);
      fill(60,100,W(r*3+c,{seed:802,t:t,range:[140,200]}));
      quad(ix-8,iy-4,ix,iy,ix,iy+h*0.5,ix-8,iy+h*0.5-4);
      fill(30,60,W(r*3+c,{seed:803,t:t,range:[100,160]}));
      quad(ix,iy,ix+8,iy-4,ix+8,iy+h*0.5-4,ix,iy+h*0.5);
    }
  }

(t) => {
    noStroke();
    for(let i=0;i<12;i++){
      const z=W(i*0.3,{wave:'sine',t:t,seed:880+i,range:[0,1]});
      const x=W(t,{wave:'noise',seed:884+i,range:[10,40]});
      const y=W(t,{wave:'noise',seed:896+i,range:[10,40]});
      fill(W(i,{seed:908+i,t:t,range:[100,255]}),150,255, z*200+30);
      ellipse(x,y, 4+z*8);
    }
  }

(t) => {
    noStroke();
    for(let seg=0;seg<6;seg++){
      const base=seg*TWO_PI/6+W(t,{wave:'sine',seed:950,range:[0,0.3]});
      for(let i=0;i<5;i++){
        const r=W(i*0.5,{wave:'bumpy sine',t:t,seed:951+seg,range:[4,20]});
        const a=base+i*0.2;
        fill((seg*60+i*30)%256,W(i,{seed:955+seg,t:t,range:[100,200]}),240,180);
        ellipse(25+cos(a)*r,25+sin(a)*r,W(i,{seed:960+seg,t:t,range:[2,6]}));
      }
    }
  }

(t) => {
    noFill(); strokeWeight(1.5);
    // Wave 1's output controls wave 2's frequency
    const freq = W(t,{wave:'sine',seed:990,range:[0.02,0.15]});
    // Wave 2's output controls wave 3's range
    stroke(255,200,100);
    beginShape();
    for(let x=0;x<50;x++){
      const mid = W(x*freq,{wave:'triangle',t:t,seed:991,range:[15,35]});
      const final = W(x*0.08,{wave:'noise',t:t,seed:992,range:[mid-8,mid+8]});
      vertex(x,final);
    }
    endShape();
    // Second chain with different waves
    stroke(100,200,255);
    beginShape();
    for(let x=0;x<50;x++){
      const phase = W(t,{wave:'ramp',seed:993,range:[0,PI]});
      const y = W(x*0.06,{wave:'wobble sine',t:t,seed:994,range:[10,40],phase:phase});
      vertex(x,y);
    }
    endShape();
  }

(t) => {
    noFill(); stroke(255,80,200); strokeWeight(1);
    beginShape();
    for(let a=0;a<=TWO_PI;a+=0.08){
      const r=W(a*2,{wave:'batman',t:t,seed:0,range:[6,20]});
      vertex(25+cos(a)*r,25+sin(a)*r);
    }
    endShape(CLOSE);
  }

(t) => {
    noFill(); stroke(255,100,50); strokeWeight(0.8);
    beginShape();
    for(let i=0;i<80;i++){
      const u=i*0.05+t*0.2;
      vertex(W(u,{wave:'wobble sine',seed:50,range:[3,47]}),
             W(u,{wave:'meta sine',seed:51,range:[3,47]}));
    }
    endShape();
  }

(t) => {
    noStroke();
    const beat=W(t,{wave:'sharp peaks',seed:100,range:[0.7,1.2]});
    fill(255,W(t,{seed:101,wave:'sine',range:[30,80]}),80);
    beginShape();
    for(let a=0;a<=TWO_PI;a+=0.05){
      const r=13*beat*(1-sin(a))*0.45;
      vertex(25+r*sin(a)*0.9,30-r*cos(a)*0.7);
    }
    endShape(CLOSE);
  }

(t) => {
    noFill(); stroke(255,200,0); strokeWeight(1);
    const teeth=floor(W(t*0.3,{wave:'steps',seed:110,range:[6,14.99]}));
    const depth=W(t,{wave:'bumpy sine',seed:111,range:[2,6]});
    translate(25,25); rotate(W(t,{wave:'saw up',seed:112,range:[0,TWO_PI]}));
    beginShape();
    for(let i=0;i<teeth*2;i++){
      const a=i*PI/teeth;
      const r=i%2===0?12+depth:12-depth;
      vertex(cos(a)*r,sin(a)*r);
    }
    endShape(CLOSE);
  }

(t) => {
    const mouth=W(t*2,{wave:'half sine',seed:150,range:[0.05,0.8]});
    fill(255,220,0); noStroke();
    arc(25,25,30,30,mouth*PI,TWO_PI-mouth*PI,PIE);
    fill(0); ellipse(27,18,4,4);
  }

(t) => {
    noStroke();
    fill(240); ellipse(25,25,42,28);
    for(let i=14;i>0;i--){
      const h=W(i*0.3,{wave:'noise',t:t*0.5,seed:190,range:[15,45]});
      const s=W(i*0.2,{seed:191,t:t,range:[60,100]});
      colorMode(HSB,360,100,100); fill(h,s,70-i*3); colorMode(RGB);
      ellipse(25,25,i*2,i*2);
    }
    const pupil=W(t,{wave:'smooth solid sine',seed:192,range:[4,10]});
    fill(0); ellipse(25,25,pupil,pupil);
    fill(255,180); ellipse(28,22,3,2);
  }

(t) => {
    colorMode(HSB,360,100,100); noStroke();
    const seeds=[];
    for(let i=0;i<6;i++) seeds.push({
      x:W(t,{seed:210+i,wave:'noise',range:[5,45]}),
      y:W(t,{seed:216+i,wave:'noise',range:[5,45]}),
      h:W(i,{seed:222+i,t:t,wave:'ramp',range:[0,360]})
    });
    for(let y=0;y<50;y+=2)for(let x=0;x<50;x+=2){
      let md=999,ms=null;
      for(let s of seeds){const d=dist(x,y,s.x,s.y);if(d<md){md=d;ms=s;}}
      fill(ms.h%360,80,max(30,90-md*2)); rect(x,y,2,2);
    }
    colorMode(RGB);
  }

(t) => {
    for(let i=0;i<6;i++){
      const y=8+i*7;
      const hue=W(i,{wave:'saw up',t:t,seed:240,range:[0,255]});
      for(let g=4;g>=0;g--){
        stroke(hue,100+g*30,255,50-g*10); strokeWeight(1+g*1.5);
        const y1=y+W(0,{wave:'noise',t:t+i,seed:241+i,range:[-2,2]});
        const y2=y+W(1,{wave:'noise',t:t+i,seed:242+i,range:[-2,2]});
        line(3,y1,47,y2);
      }
    }
  }

(t) => {
    noStroke();
    for(let y=0;y<50;y+=2)for(let x=0;x<50;x+=2){
      const heat=W((x+y*50)*0.003,{wave:'squared sine',t:t*0.4,seed:260,range:[0,1]});
      const d=dist(x,y,25+W(t,{seed:261,range:[-8,8]}),25)*0.04;
      const v=constrain(heat-d*0.3,0,1);
      if(v<0.33) fill(0,0,v*3*255);
      else if(v<0.66) fill(v*2*255,0,255-v*255);
      else fill(255,(v-0.5)*500,0);
      rect(x,y,2,2);
    }
  }

(t) => {
    stroke(150); strokeWeight(0.5);
    noFill();
    const active=floor(W(t,{wave:'square',seed:300,range:[0,1.99]}));
    for(let i=0;i<5;i++){
      let ang=0;
      if(i===0&&active===0) ang=W(t*3,{wave:'half sine',seed:301,range:[-0.6,0]});
      if(i===4&&active===1) ang=W(t*3,{wave:'half sine',seed:302,range:[0,0.6]});
      const bx=15+i*5+sin(ang)*15;
      const by=10+cos(ang)*15;
      line(15+i*5,5,bx,by);
      fill(200); ellipse(bx,by,5,5); noFill();
    }
  }

(t) => {
    // Wave surface
    noFill(); stroke(100,100,255); strokeWeight(1);
    beginShape();
    for(let x=0;x<50;x++) vertex(x,35+W(x*0.06,{wave:'bumpy sine',t:t,seed:330,range:[-5,5]}));
    endShape();
    // Ball
    const bx=W(t,{wave:'saw up',seed:331,range:[5,45]});
    const surface=35+W(bx*0.06,{wave:'bumpy sine',t:t,seed:330,range:[-5,5]});
    const bounce=abs(W(t*2,{wave:'triangle',seed:332,range:[-15,0]}));
    noStroke(); fill(255,100,100);
    ellipse(bx,surface-4-bounce,6,6);
  }

(t) => {
    stroke(200); strokeWeight(0.8);
    for(let i=0;i<7;i++){
      const len=W(i*0.3,{wave:'ramp up sine',t:t*0.1,seed:350,range:[12,35]});
      const period=sqrt(len)*0.5;
      const angle=0.5*sin(t*TWO_PI/period);
      const bx=5+i*6.5+sin(angle)*len;
      const by=3+cos(angle)*len;
      line(5+i*6.5,3,bx,by);
      noStroke();fill(W(i,{seed:351,t:t,range:[150,255]}),200,255);
      ellipse(bx,by,4,4);stroke(200);strokeWeight(0.8);
    }
  }

(t) => {
    noStroke();
    for(let i=0;i<8;i++){
      const x=5+i*5.5+W(t+i*0.3,{wave:'sine',seed:360,range:[-2,2]});
      const y=25+W(t+i*0.3,{wave:'sine',seed:361,range:[-6,6]});
      const sz=W(i*0.3,{wave:'bumpy sine',t:t,seed:362,range:[3,7]});
      fill(50,W(i,{seed:363,t:t,range:[150,255]}),50);
      ellipse(x,y,sz,sz);
    }
    // Eyes on first segment
    fill(0); ellipse(8,22,2,2); ellipse(11,22,2,2);
  }

(t) => {
    const bx=W(t,{wave:'wobble sine',seed:390,range:[5,45]});
    const by=W(t,{wave:'meta sine',seed:391,range:[5,40]});
    noStroke();fill(200); ellipse(bx,by,5,5);
    // Flippers
    stroke(255,150,0);strokeWeight(2);
    const fL=W(t*2,{wave:'pulse',seed:392,range:[-0.3,0.3]});
    push();translate(15,44);rotate(fL);line(0,0,10,-3);pop();
    push();translate(35,44);rotate(-fL);line(0,0,-10,-3);pop();
    // Bumpers
    noStroke();
    fill(W(t*4,{seed:393,wave:'square',range:[60,255]}),0,0); ellipse(15,20,6,6);
    fill(0,W(t*4,{seed:394,wave:'square',range:[60,255]}),0); ellipse(35,20,6,6);
    fill(0,0,W(t*4,{seed:395,wave:'square',range:[60,255]})); ellipse(25,12,6,6);
  }

(t) => {
    strokeWeight(0.8);
    for(let i=0;i<12;i++){
      const y=i*4+W(i*0.3,{wave:'sine',t:t,seed:400,range:[-2,2]});
      stroke(W(i,{seed:401,t:t,range:[100,255]}),100,150);
      line(0,y,50,y+W(t,{seed:402+i,wave:'noise',range:[-3,3]}));
    }
    for(let i=0;i<12;i++){
      const x=i*4+W(i*0.3,{wave:'triangle',t:t,seed:403,range:[-2,2]});
      stroke(100,W(i,{seed:404,t:t,range:[100,255]}),150);
      line(x,0,x+W(t,{seed:405+i,wave:'noise',range:[-3,3]}),50);
    }
  }

(t) => {
    noFill(); stroke(255,100,200); strokeWeight(0.6);
    const R=16,d=W(t*0.2,{wave:'sine',seed:450,range:[6,14]});
    const r=W(t*0.15,{wave:'triangle',seed:451,range:[3,8]});
    beginShape();
    for(let a=0;a<TWO_PI*5;a+=0.03){
      const x=(R-r)*cos(a)+d*cos((R-r)/r*a);
      const y=(R-r)*sin(a)-d*sin((R-r)/r*a);
      vertex(25+x,25+y);
    }
    endShape();
  }

(t) => {
    for(let i=0;i<8;i++){
      const tip=constrain(W(t-i*0.15,{wave:'ramp',seed:480,range:[-0.2,1.2]}),0,1)*HALF_PI;
      push(); translate(4+i*6,40);rotate(-tip);
      fill(W(i,{seed:481,t:t,range:[180,255]})); noStroke();
      rect(-2,-15,4,15,1);
      pop();
    }
  }

(t) => {
    const pulse=W(t*2,{wave:'half sine',seed:570,range:[0.8,1.2]});
    // Bell
    noStroke();fill(150,100,255,150);
    arc(25,18,22*pulse,18*pulse,0,PI);
    // Tentacles
    stroke(150,100,255,100);strokeWeight(0.8);noFill();
    for(let i=0;i<5;i++){
      beginShape();
      const bx=17+i*4;
      for(let j=0;j<8;j++){
        const dx=W(j*0.3,{wave:'sine',t:t+i,seed:571+i,range:[-3,3]});
        vertex(bx+dx,18+j*4);
      }
      endShape();
    }
  }

(t) => {
    noFill();stroke(0,255,100);strokeWeight(1.5);
    beginShape();
    for(let x=0;x<50;x++){
      const phase=((x*0.04+t*0.8)%1);
      let y=25;
      if(phase<0.1) y+=W(phase*30,{wave:'half sine',seed:590,range:[0,3]});
      else if(phase<0.2) y-=W((phase-0.1)*30,{wave:'sharp peaks',seed:591,range:[0,15]});
      else if(phase<0.3) y+=W((phase-0.2)*30,{wave:'half sine',seed:592,range:[0,4]});
      else y+=W(phase,{seed:593,wave:'noise',t:t,range:[-0.5,0.5]});
      vertex(x,y);
    }
    endShape();
