  stroke(255, 0, 0, W(25, {wave:'fuzzy pulse', t:t, range:[0,60], frequency:0.8})); strokeWeight(0.5);
  for (let g = 0; g < 50; g += blockSize) { line(g, 0, g, 50); line(0, g, 50, g); }
}

